# solution.py
# Event Organizer Collaborative System
# This system is designed to manage and optimize the planning and execution of various events.

class Task:
    def __init__(self, name, description, deadline, assigned_to):
        self.name = name
        self.description = description
        self.deadline = deadline
        self.assigned_to = assigned_to
        self.completed = False

    def mark_completed(self):
        self.completed = True

    def __str__(self):
        return f"Task: {self.name}, Description: {self.description}, Deadline: {self.deadline}, Assigned to: {self.assigned_to}, Completed: {self.completed}"

class Event:
    def __init__(self, name, date, budget):
        self.name = name
        self.date = date
        self.budget = budget
        self.tasks = []
        self.guests = []

    def add_task(self, task):
        self.tasks.append(task)

    def add_guest(self, guest):
        self.guests.append(guest)

    def get_tasks(self):
        return self.tasks

    def get_guests(self):
        return self.guests

    def __str__(self):
        return f"Event: {self.name}, Date: {self.date}, Budget: {self.budget}, Tasks: {len(self.tasks)}, Guests: {len(self.guests)}"

class Guest:
    def __init__(self, name, contact_info):
        self.name = name
        self.contact_info = contact_info

    def __str__(self):
        return f"Guest: {self.name}, Contact Info: {self.contact_info}"

class EventOrganizer:
    def __init__(self):
        self.events = []

    def add_event(self, event):
        self.events.append(event)

    def get_events(self):
        return self.events

    def __str__(self):
        return f"Event Organizer with {len(self.events)} events."

# Example usage
if __name__ == "__main__":
    organizer = EventOrganizer()
    event = Event("Tech Conference", "2023-12-01", 10000)
    task = Task("Setup Venue", "Setup the venue for the conference", "2023-11-25", "Alice")
    guest = Guest("John Doe", "john.doe@example.com")

    event.add_task(task)
    event.add_guest(guest)
    organizer.add_event(event)

    print(organizer)
    for event in organizer.get_events():
        print(event)
        for task in event.get_tasks():
            print(task)
        for guest in event.get_guests():
            print(guest)
```

